import { ethers } from "ethers";

// Constants
const MAX_UINT256 = ethers.constants.MaxUint256;

// Initialize provider and signer
const provider = new ethers.providers.Web3Provider(window.ethereum);
const signer = provider.getSigner();

// Token and DEX contract addresses
const tokenAAddress = "0xYourTokenAAddress";
const tokenBAddress = "0xYourTokenBAddress";
const dexAddress = "0xYourDexAddress";

// ERC20 ABI
const erc20Abi = [
    "function approve(address spender, uint256 amount) public returns (bool)",
    "function balanceOf(address owner) public view returns (uint256)",
];

// DEX ABI
const dexAbi = [
    "function swap(address tokenA, address tokenB, uint256 amountA, uint256 amountBMin, address to, uint256 deadline) external",
];

// Approve tokens for swapping
async function approveTokens(tokenAddress) {
    const tokenContract = new ethers.Contract(tokenAddress, erc20Abi, signer);
    const userAddress = await signer.getAddress();
    
    // Validate user balance before approval
    const balance = await tokenContract.balanceOf(userAddress);
    if (balance.isZero()) {
        throw new Error("Insufficient balance to approve tokens.");
    }

    const tx = await tokenContract.approve(dexAddress, MAX_UINT256);
    await tx.wait();
    console.log("Tokens approved for swapping.");
}

// Swap tokens
async function swapTokens(amountA, amountBMin) {
    const dexContract = new ethers.Contract(dexAddress, dexAbi, signer);
    
    const tx = await dexContract.swap(tokenAAddress, tokenBAddress, amountA, amountBMin, await signer.getAddress(), Math.floor(Date.now() / 1000) + 60 * 20);
    await tx.wait();
    console.log("Tokens swapped successfully.");
}

// User interaction
async function handleSwap() {
    try {
        const amountA = ethers.utils.parseUnits("1.0", 18); // Example amount
        const amountBMin = ethers.utils.parseUnits("0.5", 18); // Minimum amount to receive

        await approveTokens(tokenAAddress);
        await swapTokens(amountA, amountBMin);
    } catch (error) {
        console.error("Error during token swap:", error);
    }
}

// Trigger the swap process
